import React, { useState, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { feeAPI, studentAPI } from '../services/api';

const Fees = () => {
  const { hasRole } = useAuth();
  const [fees, setFees] = useState([]);
  const [students, setStudents] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [showDiscountModal, setShowDiscountModal] = useState(false);
  const [editingFee, setEditingFee] = useState(null);
  const [selectedFee, setSelectedFee] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [filter, setFilter] = useState({
    studentId: '',
    status: '',
    feeType: '',
    academicYear: ''
  });
  const [formData, setFormData] = useState({
    studentId: null,
    feeType: 'Tuition',
    description: '',
    amount: '',
    dueDate: '',
    academicYear: '2024-2025',
    semester: 'Fall',
    lateFee: '',
    discountAmount: '',
    discountReason: ''
  });
  const [paymentData, setPaymentData] = useState({
    paymentAmount: '',
    paymentMethod: 'Cash',
    transactionId: ''
  });
  const [discountData, setDiscountData] = useState({
    discountAmount: '',
    discountReason: ''
  });

  useEffect(() => {
    fetchFees();
    fetchStudents();
  }, []);

  const fetchFees = async () => {
    try {
      setLoading(true);
      setError(null);
      const response = await feeAPI.getAll();
      setFees(response.data);
    } catch (err) {
      console.error('Error fetching fees:', err);
      setError('Failed to fetch fees');
    } finally {
      setLoading(false);
    }
  };

  const fetchStudents = async () => {
    try {
      const response = await studentAPI.getAll();
      setStudents(response.data);
    } catch (err) {
      console.error('Error fetching students:', err);
    }
  };

  // Check if user has permission to access this page
  if (!hasRole('ADMIN') && !hasRole('FACULTY')) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <h1 className="text-2xl font-bold text-gray-900 mb-2">Access Denied</h1>
          <p className="text-gray-600">You don't have permission to access this page.</p>
        </div>
      </div>
    );
  }

  const filteredFees = fees.filter(fee => {
    if (filter.studentId && fee.student?.id !== filter.studentId) return false;
    if (filter.status && fee.status !== filter.status) return false;
    if (filter.feeType && fee.feeType !== filter.feeType) return false;
    if (filter.academicYear && fee.academicYear !== filter.academicYear) return false;
    return true;
  });

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handlePaymentInputChange = (e) => {
    const { name, value } = e.target;
    setPaymentData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleDiscountInputChange = (e) => {
    const { name, value } = e.target;
    setDiscountData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      setError(null);

      const feeData = {
        student: { id: parseInt(formData.studentId) },
        feeType: formData.feeType,
        description: formData.description,
        amount: parseFloat(formData.amount),
        dueDate: formData.dueDate,
        academicYear: formData.academicYear,
        semester: formData.semester,
        lateFee: formData.lateFee ? parseFloat(formData.lateFee) : null,
        discountAmount: formData.discountAmount ? parseFloat(formData.discountAmount) : null,
        discountReason: formData.discountReason
      };

      if (editingFee) {
        await feeAPI.update(editingFee.id, feeData);
      } else {
        await feeAPI.create(feeData);
      }

      // Refresh fees list
      await fetchFees();
      resetForm();
    } catch (err) {
      console.error('Error saving fee:', err);
      setError('Failed to save fee');
    }
  };

  const handleEdit = (fee) => {
    setEditingFee(fee);
    setFormData({
      studentId: fee.student?.id,
      feeType: fee.feeType,
      description: fee.description,
      amount: fee.amount,
      dueDate: new Date(fee.dueDate).toISOString().split('T')[0],
      academicYear: fee.academicYear,
      semester: fee.semester,
      lateFee: fee.lateFee,
      discountAmount: fee.discountAmount,
      discountReason: fee.discountReason
    });
    setShowModal(true);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this fee record?')) {
      try {
        setError(null);
        await feeAPI.delete(id);
        // Refresh fees list
        await fetchFees();
      } catch (err) {
        console.error('Error deleting fee:', err);
        setError('Failed to delete fee');
      }
    }
  };

  const handlePayment = async (e) => {
    e.preventDefault();
    try {
      setError(null);

      const paymentInfo = {
        paymentAmount: parseFloat(paymentData.paymentAmount),
        paymentMethod: paymentData.paymentMethod,
        transactionId: paymentData.transactionId
      };

      await feeAPI.processPayment(selectedFee.id, paymentInfo);

      // Refresh fees list
      await fetchFees();
      resetPaymentForm();
    } catch (err) {
      console.error('Error processing payment:', err);
      setError('Failed to process payment');
    }
  };

  const handleDiscount = async (e) => {
    e.preventDefault();
    try {
      setError(null);

      const discountInfo = {
        discountAmount: parseFloat(discountData.discountAmount),
        discountReason: discountData.discountReason
      };

      await feeAPI.applyDiscount(selectedFee.id, discountInfo);

      // Refresh fees list
      await fetchFees();
      resetDiscountForm();
    } catch (err) {
      console.error('Error applying discount:', err);
      setError('Failed to apply discount');
    }
  };

  const resetForm = () => {
    setFormData({
      studentId: null,
      feeType: 'Tuition',
      description: '',
      amount: '',
      dueDate: '',
      academicYear: '2024-2025',
      semester: 'Fall',
      lateFee: '',
      discountAmount: '',
      discountReason: ''
    });
    setEditingFee(null);
    setShowModal(false);
  };

  const resetPaymentForm = () => {
    setPaymentData({
      paymentAmount: '',
      paymentMethod: 'Cash',
      transactionId: ''
    });
    setSelectedFee(null);
    setShowPaymentModal(false);
  };

  const resetDiscountForm = () => {
    setDiscountData({
      discountAmount: '',
      discountReason: ''
    });
    setSelectedFee(null);
    setShowDiscountModal(false);
  };

  const getStatusBadge = (status) => {
    const colors = {
      Pending: 'bg-yellow-100 text-yellow-800',
      Paid: 'bg-green-100 text-green-800',
      Partial: 'bg-blue-100 text-blue-800',
      Overdue: 'bg-red-100 text-red-800',
      Cancelled: 'bg-gray-100 text-gray-800'
    };
    return colors[status] || 'bg-gray-100 text-gray-800';
  };

  const formatCurrency = (amount) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD'
    }).format(amount || 0);
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="text-lg text-gray-600">Loading fees...</div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="text-lg text-red-600">Error: {error}</div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-3xl font-bold text-gray-900">Fee Management</h1>
        <button
          onClick={() => setShowModal(true)}
          className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors flex items-center"
        >
          <svg className="h-5 w-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
          </svg>
          Add Fee
        </button>
      </div>

      {/* Filters */}
      <div className="bg-white shadow-lg rounded-lg p-6 mb-6">
        <h3 className="text-lg font-semibold text-gray-900 mb-4">Filters</h3>
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700">Student</label>
            <select
              value={filter.studentId}
              onChange={(e) => setFilter(prev => ({ ...prev, studentId: e.target.value }))}
              className="mt-1 block w-full border border-gray-300 rounded-md px-3 py-2"
            >
              <option value="">All Students</option>
              {students.map(student => (
                <option key={student.id} value={student.id}>
                  {student.firstName} {student.lastName}
                </option>
              ))}
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700">Status</label>
            <select
              value={filter.status}
              onChange={(e) => setFilter(prev => ({ ...prev, status: e.target.value }))}
              className="mt-1 block w-full border border-gray-300 rounded-md px-3 py-2"
            >
              <option value="">All Status</option>
              <option value="Pending">Pending</option>
              <option value="Paid">Paid</option>
              <option value="Partial">Partial</option>
              <option value="Overdue">Overdue</option>
              <option value="Cancelled">Cancelled</option>
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700">Fee Type</label>
            <select
              value={filter.feeType}
              onChange={(e) => setFilter(prev => ({ ...prev, feeType: e.target.value }))}
              className="mt-1 block w-full border border-gray-300 rounded-md px-3 py-2"
            >
              <option value="">All Types</option>
              <option value="Tuition">Tuition</option>
              <option value="Library">Library</option>
              <option value="Lab">Lab</option>
              <option value="Hostel">Hostel</option>
              <option value="Transport">Transport</option>
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700">Academic Year</label>
            <select
              value={filter.academicYear}
              onChange={(e) => setFilter(prev => ({ ...prev, academicYear: e.target.value }))}
              className="mt-1 block w-full border border-gray-300 rounded-md px-3 py-2"
            >
              <option value="">All Years</option>
              <option value="2024-2025">2024-2025</option>
              <option value="2023-2024">2023-2024</option>
            </select>
          </div>
        </div>
      </div>

      {/* Fees Table */}
      <div className="bg-white shadow-lg rounded-lg overflow-hidden">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">ID</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Student</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Fee Type</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Amount</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Paid</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Remaining</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Due Date</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {filteredFees.length === 0 ? (
                <tr>
                  <td colSpan="9" className="px-6 py-12 text-center text-gray-500">
                    No fees found matching your filters.
                  </td>
                </tr>
              ) : (
                filteredFees.map((fee) => (
                  <tr key={fee.id} className="hover:bg-gray-50">
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                      {fee.id}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {fee.student?.firstName} {fee.student?.lastName}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {fee.feeType}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {formatCurrency(fee.amount)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {formatCurrency(fee.paidAmount || 0)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {formatCurrency(fee.getRemainingAmount)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {new Date(fee.dueDate).toLocaleDateString()}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${getStatusBadge(fee.status)}`}>
                        {fee.status}
                      </span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                      <button
                        onClick={() => handleEdit(fee)}
                        className="text-indigo-600 hover:text-indigo-900 mr-2 transition-colors"
                      >
                        Edit
                      </button>
                      <button
                        onClick={() => {
                          setSelectedFee(fee);
                          setShowPaymentModal(true);
                        }}
                        className="text-green-600 hover:text-green-900 mr-2 transition-colors"
                        disabled={fee.status === 'Paid'}
                      >
                        Pay
                      </button>
                      <button
                        onClick={() => {
                          setSelectedFee(fee);
                          setShowDiscountModal(true);
                        }}
                        className="text-yellow-600 hover:text-yellow-900 mr-2 transition-colors"
                        disabled={fee.status === 'Paid'}
                      >
                        Discount
                      </button>
                      <button
                        onClick={() => handleDelete(fee.id)}
                        className="text-red-600 hover:text-red-900 transition-colors"
                      >
                        Delete
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Add/Edit Fee Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-gray-600 bg-opacity-50 overflow-y-auto h-full w-full z-50">
          <div className="relative top-20 mx-auto p-5 border w-96 shadow-lg rounded-md bg-white">
            <div className="mt-3">
              <h3 className="text-lg leading-6 font-medium text-gray-900">
                {editingFee ? 'Edit Fee' : 'Add New Fee'}
              </h3>
              <div className="mt-2">
                <form onSubmit={handleSubmit}>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="mb-4">
                      <label className="block text-sm font-medium text-gray-700">Student</label>
                      <select
                        name="studentId"
                        value={formData.studentId}
                        onChange={handleInputChange}
                        className="mt-1 block w-full border border-gray-300 rounded-md px-3 py-2"
                        required
                      >
                        <option value="">Select Student</option>
                        {students.map(student => (
                          <option key={student.id} value={student.id}>
                            {student.firstName} {student.lastName}
                          </option>
                        ))}
                      </select>
                    </div>
                    <div className="mb-4">
                      <label className="block text-sm font-medium text-gray-700">Fee Type</label>
                      <select
                        name="feeType"
                        value={formData.feeType}
                        onChange={handleInputChange}
                        className="mt-1 block w-full border border-gray-300 rounded-md px-3 py-2"
                      >
                        <option value="Tuition">Tuition</option>
                        <option value="Library">Library</option>
                        <option value="Lab">Lab</option>
                        <option value="Hostel">Hostel</option>
                        <option value="Transport">Transport</option>
                      </select>
                    </div>
                  </div>
                  <div className="mb-4">
                    <label className="block text-sm font-medium text-gray-700">Description</label>
                    <textarea
                      name="description"
                      value={formData.description}
                      onChange={handleInputChange}
                      rows="3"
                      className="mt-1 block w-full border border-gray-300 rounded-md px-3 py-2"
                    />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="mb-4">
                      <label className="block text-sm font-medium text-gray-700">Amount</label>
                      <input
                        type="number"
                        name="amount"
                        value={formData.amount}
                        onChange={handleInputChange}
                        className="mt-1 block w-full border border-gray-300 rounded-md px-3 py-2"
                        required
                      />
                    </div>
                    <div className="mb-4">
                      <label className="block text-sm font-medium text-gray-700">Due Date</label>
                      <input
                        type="date"
                        name="dueDate"
                        value={formData.dueDate}
                        onChange={handleInputChange}
                        className="mt-1 block w-full border border-gray-300 rounded-md px-3 py-2"
                        required
                      />
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="mb-4">
                      <label className="block text-sm font-medium text-gray-700">Academic Year</label>
                      <select
                        name="academicYear"
                        value={formData.academicYear}
                        onChange={handleInputChange}
                        className="mt-1 block w-full border border-gray-300 rounded-md px-3 py-2"
                      >
                        <option value="2024-2025">2024-2025</option>
                        <option value="2023-2024">2023-2024</option>
                      </select>
                    </div>
                    <div className="mb-4">
                      <label className="block text-sm font-medium text-gray-700">Semester</label>
                      <select
                        name="semester"
                        value={formData.semester}
                        onChange={handleInputChange}
                        className="mt-1 block w-full border border-gray-300 rounded-md px-3 py-2"
                      >
                        <option value="Fall">Fall</option>
                        <option value="Spring">Spring</option>
                        <option value="Summer">Summer</option>
                      </select>
                    </div>
                  </div>
                  <div className="flex justify-end space-x-2 mt-6">
                    <button
                      type="button"
                      onClick={resetForm}
                      className="bg-gray-300 text-gray-700 px-4 py-2 rounded-md hover:bg-gray-400 transition-colors"
                    >
                      Cancel
                    </button>
                    <button
                      type="submit"
                      className="bg-blue-600 text-white px-4 py-2 rounded-md hover:bg-blue-700 transition-colors"
                    >
                      {editingFee ? 'Update' : 'Add'} Fee
                    </button>
                  </div>
                </form>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Payment Modal */}
      {showPaymentModal && selectedFee && (
        <div className="fixed inset-0 bg-gray-600 bg-opacity-50 overflow-y-auto h-full w-full z-50">
          <div className="relative top-20 mx-auto p-5 border w-96 shadow-lg rounded-md bg-white">
            <div className="mt-3">
              <h3 className="text-lg leading-6 font-medium text-gray-900">
                Process Payment for {selectedFee.student?.firstName} {selectedFee.student?.lastName}
              </h3>
              <div className="mt-2">
                <div className="mb-4 p-4 bg-gray-50 rounded">
                  <p className="text-sm text-gray-600">Fee Type: <span className="font-medium">{selectedFee.feeType}</span></p>
                  <p className="text-sm text-gray-600">Amount: <span className="font-medium">{formatCurrency(selectedFee.amount)}</span></p>
                  <p className="text-sm text-gray-600">Paid: <span className="font-medium">{formatCurrency(selectedFee.paidAmount || 0)}</span></p>
                  <p className="text-sm text-gray-600">Remaining: <span className="font-medium">{formatCurrency(selectedFee.getRemainingAmount)}</span></p>
                </div>
                <form onSubmit={handlePayment}>
                  <div className="mb-4">
                    <label className="block text-sm font-medium text-gray-700">Payment Amount</label>
                    <input
                      type="number"
                      name="paymentAmount"
                      value={paymentData.paymentAmount}
                      onChange={handlePaymentInputChange}
                      className="mt-1 block w-full border border-gray-300 rounded-md px-3 py-2"
                      max={selectedFee.getRemainingAmount()}
                      required
                    />
                  </div>
                  <div className="mb-4">
                    <label className="block text-sm font-medium text-gray-700">Payment Method</label>
                    <select
                      name="paymentMethod"
                      value={paymentData.paymentMethod}
                      onChange={handlePaymentInputChange}
                      className="mt-1 block w-full border border-gray-300 rounded-md px-3 py-2"
                    >
                      <option value="Cash">Cash</option>
                      <option value="Card">Card</option>
                      <option value="Bank Transfer">Bank Transfer</option>
                      <option value="Online">Online</option>
                    </select>
                  </div>
                  <div className="mb-4">
                    <label className="block text-sm font-medium text-gray-700">Transaction ID</label>
                    <input
                      type="text"
                      name="transactionId"
                      value={paymentData.transactionId}
                      onChange={handlePaymentInputChange}
                      className="mt-1 block w-full border border-gray-300 rounded-md px-3 py-2"
                    />
                  </div>
                  <div className="flex justify-end space-x-2 mt-6">
                    <button
                      type="button"
                      onClick={resetPaymentForm}
                      className="bg-gray-300 text-gray-700 px-4 py-2 rounded-md hover:bg-gray-400 transition-colors"
                    >
                      Cancel
                    </button>
                    <button
                      type="submit"
                      className="bg-green-600 text-white px-4 py-2 rounded-md hover:bg-green-700 transition-colors"
                    >
                      Process Payment
                    </button>
                  </div>
                </form>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Discount Modal */}
      {showDiscountModal && selectedFee && (
        <div className="fixed inset-0 bg-gray-600 bg-opacity-50 overflow-y-auto h-full w-full z-50">
          <div className="relative top-20 mx-auto p-5 border w-96 shadow-lg rounded-md bg-white">
            <div className="mt-3">
              <h3 className="text-lg leading-6 font-medium text-gray-900">
                Apply Discount for {selectedFee.student?.firstName} {selectedFee.student?.lastName}
              </h3>
              <div className="mt-2">
                <div className="mb-4 p-4 bg-gray-50 rounded">
                  <p className="text-sm text-gray-600">Fee Type: <span className="font-medium">{selectedFee.feeType}</span></p>
                  <p className="text-sm text-gray-600">Amount: <span className="font-medium">{formatCurrency(selectedFee.amount)}</span></p>
                  <p className="text-sm text-gray-600">Remaining: <span className="font-medium">{formatCurrency(selectedFee.getRemainingAmount)}</span></p>
                </div>
                <form onSubmit={handleDiscount}>
                  <div className="mb-4">
                    <label className="block text-sm font-medium text-gray-700">Discount Amount</label>
                    <input
                      type="number"
                      name="discountAmount"
                      value={discountData.discountAmount}
                      onChange={handleDiscountInputChange}
                      className="mt-1 block w-full border border-gray-300 rounded-md px-3 py-2"
                      max={selectedFee.getRemainingAmount()}
                      required
                    />
                  </div>
                  <div className="mb-4">
                    <label className="block text-sm font-medium text-gray-700">Discount Reason</label>
                    <textarea
                      name="discountReason"
                      value={discountData.discountReason}
                      onChange={handleDiscountInputChange}
                      rows="3"
                      className="mt-1 block w-full border border-gray-300 rounded-md px-3 py-2"
                      required
                    />
                  </div>
                  <div className="flex justify-end space-x-2 mt-6">
                    <button
                      type="button"
                      onClick={resetDiscountForm}
                      className="bg-gray-300 text-gray-700 px-4 py-2 rounded-md hover:bg-gray-400 transition-colors"
                    >
                      Cancel
                    </button>
                    <button
                      type="submit"
                      className="bg-yellow-600 text-white px-4 py-2 rounded-md hover:bg-yellow-700 transition-colors"
                    >
                      Apply Discount
                    </button>
                  </div>
                </form>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Fees;
